def main(follower_count: int, following_count: int, post_count: int) -> dict:
    # Calculate follower/following ratio
    ff_ratio = follower_count / max(following_count, 1)

    # Calculate engagement potential
    if follower_count > 0:
        engagement_ratio = post_count / follower_count * 100
    else:
        engagement_ratio = 0

    # Determine account type
    if ff_ratio > 2:
        account_type = 'influencer'
    elif ff_ratio < 0.3:
        account_type = 'mass_follower'
    else:
        account_type = 'normal'

    return {
        'ff_ratio': round(ff_ratio, 2),
        'engagement_ratio': round(engagement_ratio, 2),
        'account_type': account_type
    }

def main(ff_ratio: float, account_type: str, is_verified: bool, is_private: bool, relevance_score: int, red_flags: list, post_count: int) -> dict:
    score = 50  # Base score

    # Follower/following ratio impact
    if 0.5 <= ff_ratio <= 3:
        score += 15  # Good ratio
    elif ff_ratio > 10:
        score += 10  # Micro-influencer
    elif ff_ratio < 0.2:
        score -= 20  # Mass follower

    # Activity impact
    if post_count >= 10:
        score += 10
    elif post_count == 0:
        score -= 15  # Inactive

    # Verification bonus
    if is_verified:
        score += 10

    # Private account penalty
    if is_private:
        score -= 10

    # Bio relevance
    score += relevance_score * 0.2

    # Red flags penalty
    score -= len(red_flags) * 5

    # Normalize score
    score = max(0, min(100, score))

    # Determine tier
    if score >= 70:
        tier = 'high'
    elif score >= 40:
        tier = 'medium'
    else:
        tier = 'low'

    return {
        'quality_score': int(score),
        'quality_tier': tier,
        'recommendation': 'priority_outreach' if tier == 'high' else 'standard_outreach' if tier == 'medium' else 'skip'
    }
